@@ -3150,6 +3150,46 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     }
   }

+  // Handle pattern: select (select C1, C2, false), V1, (select C1, V2, V3)
+  // This is: if (C1 && C2) V1 else (if C1 V2 else V3)
+  // Transforms to: select C1, (select C2, V1, V2), V3
+  // Which is: if C1 (if C2 V1 else V2) else V3
+  if (SelectInst *CondSI = dyn_cast<SelectInst>(CondVal)) {
+    // Condition is: select C1, C2, false (representing C1 && C2)
+    if (match(CondSI->getFalseValue(), m_Zero())) {
+      Value *C1 = CondSI->getCondition();
+      Value *C2 = CondSI->getTrueValue();
+      // Check if false value is a select with the same condition C1
+      if (SelectInst *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
+        if (FalseSI->getCondition() == C1 && CondSI->hasOneUse() && FalseSI->hasOneUse()) {
+          // Both have exactly one use - can eliminate both intermediate selects
+          Value *InnerSel = Builder.CreateSelect(C2, TrueVal, FalseSI->getTrueValue());
+          return SelectInst::Create(C1, InnerSel, FalseSI->getFalseValue());
+        }
+      }
+    }
+  }
+
+  // Handle pattern: select (select C1, true, C2), (select C1, V1, V2), V3
+  // This is: if (C1 || C2) (if C1 V1 else V2) else V3
+  // Transforms to: select C1, V1, (select C2, V2, V3)
+  // Which is: if C1 V1 else (if C2 V2 else V3)
+  if (SelectInst *CondSI = dyn_cast<SelectInst>(CondVal)) {
+    // Condition is: select C1, true, C2 (representing C1 || C2)
+    if (match(CondSI->getTrueValue(), m_One())) {
+      Value *C1 = CondSI->getCondition();
+      Value *C2 = CondSI->getFalseValue();
+      // Check if true value is a select with the same condition C1
+      if (SelectInst *TrueSI = dyn_cast<SelectInst>(TrueVal)) {
+        if (TrueSI->getCondition() == C1 && CondSI->hasOneUse() && TrueSI->hasOneUse()) {
+          // Both have exactly one use - can eliminate both intermediate selects
+          Value *InnerSel = Builder.CreateSelect(C2, TrueSI->getFalseValue(), FalseVal);
+          return SelectInst::Create(C1, TrueSI->getTrueValue(), InnerSel);
+        }
+      }
+    }
+  }
